package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.DuplicateFollowException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.exception.UserNotFoundException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followeeId: String): FollowEntity {
        // 자기 자신 팔로우 방지
        if (followerId == followeeId) {
            throw SelfFollowException()
        }

        // 팔로워 존재 여부 확인
        if (!userRepository.existsById(followerId)) {
            throw UserNotFoundException(followerId)
        }

        // 팔로위 존재 여부 확인
        if (!userRepository.existsById(followeeId)) {
            throw UserNotFoundException(followeeId)
        }

        // 중복 팔로우 방지
        val existing = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
        if (existing != null) {
            throw DuplicateFollowException(followerId, followeeId)
        }

        val follow = FollowEntity(
            followerId = followerId,
            followeeId = followeeId,
        )
        return followRepository.save(follow)
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        val follow = followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId)
            ?: throw IllegalStateException("팔로우 관계가 존재하지 않습니다: $followerId -> $followeeId")

        followRepository.delete(follow)
    }

    @Transactional(readOnly = true)
    fun getFollowings(followerId: String): List<FollowEntity> {
        if (!userRepository.existsById(followerId)) {
            throw UserNotFoundException(followerId)
        }
        return followRepository.findByFollowerId(followerId)
    }

    @Transactional(readOnly = true)
    fun getFollowers(followeeId: String): List<FollowEntity> {
        if (!userRepository.existsById(followeeId)) {
            throw UserNotFoundException(followeeId)
        }
        return followRepository.findByFolloweeId(followeeId)
    }

    @Transactional(readOnly = true)
    fun isFollowing(followerId: String, followeeId: String): Boolean {
        return followRepository.findByFollowerIdAndFolloweeId(followerId, followeeId) != null
    }
}
